import{_ as t,o as s,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Request & Approve Restores","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/restore-requests.md","filePath":"how-to/restore-requests.md"}'),o={name:"how-to/restore-requests.md"};function i(l,e,n,h,p,d){return s(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="request-approve-restores" tabindex="-1">Request &amp; Approve Restores <a class="header-anchor" href="#request-approve-restores" aria-label="Permalink to &quot;Request &amp; Approve Restores&quot;">​</a></h1><p>This guide explains the restore-request flow for users who cannot restore something directly, and for the senior roles who approve those requests.</p><p><code>King</code>, <code>Alliance Leader</code>, and <code>Supreme Admin</code> users are the usual approvers. Other users may only be able to file the request.</p><blockquote><p>Screenshot placeholder: <code>restore-requests.png</code> (S46)</p></blockquote><h2 id="the-short-version" tabindex="-1">The short version <a class="header-anchor" href="#the-short-version" aria-label="Permalink to &quot;The short version&quot;">​</a></h2><p>If you can see a deleted item but do not have restore permission, use <strong>Request restore</strong>. An approver reviews it and either restores the item or rejects the request.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;User finds deleted item&quot;] --&gt; B[&quot;Request restore&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;Pending restore request&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;Approve&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; E[&quot;Reject&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[&quot;Item restored&quot;]</span></span></code></pre></div><h2 id="for-requesters" tabindex="-1">For requesters <a class="header-anchor" href="#for-requesters" aria-label="Permalink to &quot;For requesters&quot;">​</a></h2><ol><li>Open the relevant deleted item or bin area.</li><li>Choose <strong>Request restore</strong>.</li><li>Wait for an approver to review it.</li></ol><h2 id="for-approvers" tabindex="-1">For approvers <a class="header-anchor" href="#for-approvers" aria-label="Permalink to &quot;For approvers&quot;">​</a></h2><ol><li>Open the restore requests queue.</li><li>Review the item and the request context.</li><li>Choose <strong>Approve</strong> to restore the item, or <strong>Reject</strong> to refuse it.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./delete-restore-player.html">Delete &amp; Restore a Player</a></li><li><a href="./delete-restore-kingdom-alliance.html">Delete &amp; Restore Kingdoms/Alliances</a></li></ul>`,14)])])}const q=t(o,[["render",i]]);export{c as __pageData,q as default};
